const handleSubmit = async (e) => {
  e.preventDefault();

  if (!departure.trim() || !arrival.trim()) {
    alert("Заполните оба поля");
    return;
  }

  try {
    const res = await fetch("http://localhost:5000/routes", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ departure_station: departure, arrival_station: arrival })
    });

    const data = await res.json();

    console.log("Статус:", res.status);
    console.log("Ответ:", data);

    if (!res.ok) {
      alert(data.message || data || `Ошибка ${res.status}`);
      return;
    }

    alert("Маршрут добавлен ✅");
    setDeparture("");
    setArrival("");

  } catch (err) {
    console.error("Fetch error:", err);
    alert(`Ошибка соединения: ${err.message}\n(скорее всего проблема CORS или сервер не запущен)`);
  }
};
